/**
	 * Executes spam protections.
	 *
	 * @return bool True if spam captured.
	 */
function spam() {
		$spam = false;

		$skip_spam_check = apply_filters( 'wpcf7_skip_spam_check',
			$this->skip_spam_check,
			$this
		);

		if ( $skip_spam_check ) {
			return $spam;
		}

		if ( $this->contact_form->is_true( 'subscribers_only' )
		and current_user_can( 'wpcf7_submit', $this->contact_form->id() ) ) {
			return $spam;
		}

		$user_agent = (string) $this->get_meta( 'user_agent' );

		if ( strlen( $user_agent ) < 2 ) {
			$spam = true;

			$this->add_spam_log( array(
				'agent' => 'wpcf7',
				'reason' => __( "User-Agent string is unnaturally short.", 'contact-form-7' ),
			) );
		}

		if ( ! $this->verify_nonce() ) {
			$spam = true;

			$this->add_spam_log( array(
				'agent' => 'wpcf7',
				'reason' => __( "Submitted nonce is invalid.", 'contact-form-7' ),
			) );
		}

		return apply_filters( 'wpcf7_spam', $spam, $this );
	}

function test_autopay_version() {
		$current_version = blue_media()->get_plugin_version();
		$remote_url      = 'https://api.wordpress.org/plugins/info/1.0/platnosci-online-blue-media.json';
		$response        = wp_remote_get( $remote_url, [ 'timeout' => 5 ] );
		if ( is_wp_error( $response ) ) {
			return new Log_Entry(
				Log_Entry::LEVEL_INFO,
				Log_Entry::get_header_info(),
				__( "Unable to fetch the latest Autopay plugin version from the WordPress repository.",
					"bm-woocommerce" )
			);
		}
		$body = wp_remote_retrieve_body( $response );
		$data = json_decode( $body );
		if ( empty( $data ) || empty( $data->version ) ) {
			return null;
		}
		$latest_version = $data->version;
		if ( version_compare( $current_version, $latest_version, '<' ) ) {
			return new Log_Entry(
				Log_Entry::LEVEL_WARNING,
				Log_Entry::get_header_warning(),
				sprintf( __( "An update is available for the Autopay plugin. Current version: %s, latest version: %s.",
					"bm-woocommerce" ),
					$current_version,
					$latest_version )
			);
		} else {
			return null;
		}
	}

